// Public-facing Worker

export default {
  async fetch(request, env) {
    // Forward request to processing worker
    const response = await env.PROCESSING_WORKER.fetch(request);
    return response;
  },
};

// Processing Worker

export default {
  async fetch(request, env) {
    // Process request and forward to another internal worker
    const response = await env.DATA_WORKER.fetch(request);
    return response;
  },
};

// Data Worker

export default {
  async fetch(request, env) {
    // Final processing of request
    const data = { message: "Request processed successfully!" };
    return new Response(JSON.stringify(data), {
      headers: { "Content-Type": "application/json" },
    });
  },
};

